-- ============================================================================
-- MIGRATION: backfill NPS responses (Welcome Trips) — Forms histórico
-- Date: 2026-05-14
--
-- Importa 201 respostas históricas do formulário "Avaliando sua
-- experiência Welcome Trips" coletadas entre dez/2024 e 31/mar/2026.
--
-- Captura as 3 perguntas do form:
--   1. Nota NPS (0-10)         → nps_responses.score
--   2. Experiência (texto livre) → nps_responses.comment
--   3. Próximo destino           → nps_responses.proximo_destino
--
-- Comportamento:
--   • Toda linha é inserida (mesmo sem card vinculado).
--   • Tenta matching por nome normalizado (lower + unaccent + trim + colapsa
--     espaços) contra cards de Welcome Trips → contatos (pessoa_principal_id).
--   • Empate: pega o card mais recente (created_at DESC).
--   • Sem match: card_id e contact_id ficam NULL; org_id é Welcome Trips
--     mesmo assim. UI renderiza essas linhas como "Sem card vinculado".
--
-- Idempotência: ON CONFLICT (source_external_id) DO NOTHING.
-- Channel = 'form' (formulário externo, não disparado pelo CRM).
-- ============================================================================

BEGIN;

CREATE EXTENSION IF NOT EXISTS unaccent;

DO $$
DECLARE
  v_org_id        UUID;
  v_matched_count INT := 0;
  v_unlinked_count INT := 0;
  r_row           RECORD;
  v_card_id       UUID;
  v_contact_id    UUID;
  v_survey_id     UUID;
BEGIN
  SELECT id INTO v_org_id FROM public.organizations WHERE slug = 'welcome-trips' LIMIT 1;
  IF v_org_id IS NULL THEN
    RAISE NOTICE 'Welcome Trips org não encontrada — backfill abortado';
    RETURN;
  END IF;

  FOR r_row IN
    WITH source (source_external_id, responded_at, full_name, score, comment, proximo_destino, raw_payload) AS (
      VALUES
  ('forms_welcome_trips_1', TIMESTAMPTZ '2024-12-06 13:07:40', 'Carine Cardoso', 10, 'Teste', 'Teste', '{"original_name": "Carine Cardoso", "proximo_destino": "Teste"}'::jsonb),
  ('forms_welcome_trips_3', TIMESTAMPTZ '2025-01-10 17:15:04', 'Marcelo Gregio de Aveiro', 10, 'Fui muito bem atendido.', 'Ainda não sei. Como usamos esses dados?', '{"original_name": "Marcelo Gregio de Aveiro", "proximo_destino": "Ainda não sei. Como usamos esses dados?"}'::jsonb),
  ('forms_welcome_trips_4', TIMESTAMPTZ '2025-01-10 17:21:25', 'Ana Julia Bertollo Poiani', 10, 'Sem palavras pra expressar o quanto vocês foram essenciais pra nossa viagem dar certo! Mudamos todo o roteiro sem custo adicional e foi maravilhoso! Todo o suporte durante a viagem nos fez sentir super seguros e os hoteis foram maravilhosos!! Ainda tivemos um voo cancelado e remarcamos um tour sem problemas. Único ponto importante para viagens futuras: nos enviaram impressos o application do visto indiano, mas o correto deveria ter sido o visto mesmo. Imprimimos no aeroporto mesmo e deu certo, mas só fica esse ponto de atenção pras próximas', 'Fiji', '{"original_name": "Ana Julia Bertollo Poiani", "proximo_destino": "Fiji"}'::jsonb),
  ('forms_welcome_trips_5', TIMESTAMPTZ '2025-01-10 17:25:35', 'Fernanda Cristina Sanchez Machado', 10, 'Nossa experiência com vocês foi maravilhosa .
Correu tudo certinho 😉', 'Inglaterra', '{"original_name": "Fernanda Cristina Sanchez Machado", "proximo_destino": "Inglaterra"}'::jsonb),
  ('forms_welcome_trips_6', TIMESTAMPTZ '2025-01-10 20:34:42', 'Maria Goreti Rudolfo Hang', 10, 'Tudo maravilhoso, ótimas indicações de hotel. E o transfer na hora certa é muito educados, o aplicativo é maravilhoso. Parabéns  a todos', NULL, '{"original_name": "Maria Goreti Rudolfo Hang"}'::jsonb),
  ('forms_welcome_trips_7', TIMESTAMPTZ '2025-01-10 23:11:02', 'Tamara Zugman Knopfholz', 10, NULL, NULL, '{"original_name": "Tamara Zugman Knopfholz"}'::jsonb),
  ('forms_welcome_trips_8', TIMESTAMPTZ '2025-01-11 00:37:18', 'Tiago Abdul Hak', 10, 'Excelente', 'Atacama', '{"original_name": "Tiago Abdul Hak", "proximo_destino": "Atacama"}'::jsonb),
  ('forms_welcome_trips_9', TIMESTAMPTZ '2025-01-11 09:42:11', 'Luciane Maria Schmaedecke Güntzel', 10, 'Sempre muito satisfeita com o atendimento da agência. Dani muito querida e prestativa.', 'Suíça', '{"original_name": "Luciane Maria Schmaedecke Güntzel", "proximo_destino": "Suíça"}'::jsonb),
  ('forms_welcome_trips_10', TIMESTAMPTZ '2025-01-14 10:15:48', 'Marcia Burgel', 10, 'Deu tudo certo, única coisa poderiam dar mais tempo para o Transfer, qdo chegamos em Orlando tínhamos 45 min. para pegar e como atrasou o voo e também a entrega de bagagem perdemos o Transfer e tivemos que pagar um outro para levarmos no hotel.', 'Cruzeiro Antártida', '{"original_name": "Marcia Burgel", "proximo_destino": "Cruzeiro Antártida"}'::jsonb),
  ('forms_welcome_trips_11', TIMESTAMPTZ '2025-01-14 15:29:36', 'Janaina Adamo de Andrade', 10, 'Oiee sou a Jana, passando para agradecer a toda equipe tivemos ótimo atendimento e suporte! Em especial a Dani não mediu esforços para que tudo desse certo! Gratidão a todos 🙏🏻😘', 'Itália, Portugal, Orlando', '{"original_name": "Janaina Adamo de Andrade", "proximo_destino": "Itália, Portugal, Orlando"}'::jsonb),
  ('forms_welcome_trips_12', TIMESTAMPTZ '2025-01-31 16:25:03', 'Leonardo Weihermann', 10, 'Ótimo atendimento, sistema AXUS muito bom. Fui atendido pela Júlia que foi muito prestativa e simpática. Nota 1000!', NULL, '{"original_name": "Leonardo Weihermann"}'::jsonb),
  ('forms_welcome_trips_13', TIMESTAMPTZ '2025-01-31 17:36:38', 'Maria Regina Tenório de Souza Calado', 10, 'Muito boa. Não tivemos nenhum contratempo.Aina', 'Ainda não pensei.', '{"original_name": "Maria Regina Tenório de Souza Calado", "proximo_destino": "Ainda não pensei."}'::jsonb),
  ('forms_welcome_trips_14', TIMESTAMPTZ '2025-02-01 22:02:59', 'Carla Miranda Rosa', 7, 'O pré vendas foi maravilhoso, a Camila foi espetacular e toda a parte de organização da viagem me deixou encantada, mas tivemos problemas de cancelamento de voo e também da minha mãe não conseguir embarcar por não ter levado o passaporte com o visto e senti um pouco de falta de acolhimento neste momento de stress e tensão. Durante a viagem a agência nos apoiou com a remarcação do hotel para não perdermos a diária ( o que foi ótimo) mas não tivemos acompanhamento se os voos de volta estavam certo e acabamos tendo que resolver o problema do cancelamento e remarcação sozinhos e acabamos tendo assentos todos separados em quase todos os voos,
fora a perda total do valor investido na viagem da minha mãe sem sequer alguma tentativa de reembolso junto a Cia Aérea ou ao Hotel.', 'Maldivas e Dubai', '{"original_name": "Carla Miranda Rosa", "proximo_destino": "Maldivas e Dubai"}'::jsonb),
  ('forms_welcome_trips_15', TIMESTAMPTZ '2025-02-21 17:46:30', 'Elizabeth Santos', 10, 'Agência muito boa com boa agente de viagem Bárbara', NULL, '{"original_name": "Elizabeth Santos"}'::jsonb),
  ('forms_welcome_trips_16', TIMESTAMPTZ '2025-02-21 17:54:09', 'Wander Jesus', 9, 'A experiência foi muito boa! Superou as expectativas! 
Um ponto de melhoria é o acompanhamento e suporte quando estamos na viagem!', NULL, '{"original_name": "Wander Jesus"}'::jsonb),
  ('forms_welcome_trips_17', TIMESTAMPTZ '2025-02-21 17:57:40', 'Roberta pires', 10, 'São super atenciosas, tiraram todas as nossas dúvidas e fizeram indicações de vários lugares!', 'Ainda não sei', '{"original_name": "Roberta pires", "proximo_destino": "Ainda não sei"}'::jsonb),
  ('forms_welcome_trips_18', TIMESTAMPTZ '2025-02-21 18:56:17', 'Marco Mendia', 6, 'Já viajei varias vezes com a Welcome Trips, porém essa vez não foi uma experiência 100%', 'Estados Unidos em setembro/25', '{"original_name": "Marco Mendia", "proximo_destino": "Estados Unidos em setembro/25"}'::jsonb),
  ('forms_welcome_trips_19', TIMESTAMPTZ '2025-02-21 19:42:11', 'Carolina Schlachta Parreira da Silva', 10, 'Tudo perfeito!', NULL, '{"original_name": "Carolina Schlachta Parreira da Silva"}'::jsonb),
  ('forms_welcome_trips_20', TIMESTAMPTZ '2025-02-21 22:18:36', 'Eduardo Rodrigues', 10, 'Foi maravilhoso, meu voo, estadia , passeios, uma experiência incrível, obrigado!', 'Indonesia', '{"original_name": "Eduardo Rodrigues", "proximo_destino": "Indonesia"}'::jsonb),
  ('forms_welcome_trips_21', TIMESTAMPTZ '2025-02-22 10:33:51', 'Agata Rebeca Alves Cordeiro', 10, 'Fomos super bem atendidas pela Barbara. Desde o início ela entendeu direitinho como queríamos que fosse nossa viagem e ela trouxe opções ótimas que super atenderam nossas expectativas. Não temos nenhuma crítica mesmo, pois tudo ocorreu da melhor maneira possível. Ficamos encantadas com o carinho de vocês antes e depois da viagem! Foi minha terceira vez viajando com a Welcome e já estamos pensando para onde iremos ano que vem com vocês de novo.', 'África ou Finlândia.', '{"original_name": "Agata Rebeca Alves Cordeiro", "proximo_destino": "África ou Finlândia."}'::jsonb),
  ('forms_welcome_trips_22', TIMESTAMPTZ '2025-02-22 15:57:54', 'Vania Paula Winnikes Bunick', 10, 'Foi tudo perfeito!', 'Ainda não definido', '{"original_name": "Vania Paula Winnikes Bunick", "proximo_destino": "Ainda não definido"}'::jsonb),
  ('forms_welcome_trips_23', TIMESTAMPTZ '2025-02-22 23:54:16', 'Raquel Pires Sasaki', 10, 'Que experiência incrível! ✨ Das águas cristalinas das Maldivas ao luxo e grandiosidade de Dubai, cada instante dessa viagem foi inesquecível! 🏝️🏙️ Sou imensamente grata à @welcometrips por todo o cuidado e dedicação em cada detalhe, transformando esse sonho em realidade! Já contando os dias para a próxima aventura! ✈️💙 #Maldivas #Dubai #WelcomeTrips #ViagemInesquecível', 'Ainda estou analisando', '{"original_name": "Raquel Pires Sasaki", "proximo_destino": "Ainda estou analisando"}'::jsonb),
  ('forms_welcome_trips_24', TIMESTAMPTZ '2025-02-24 20:07:34', 'Margareth Teixeira Grochevits', 10, 'Vocês estão de parabéns, muitos atenciosas!', NULL, '{"original_name": "Margareth Teixeira Grochevits"}'::jsonb),
  ('forms_welcome_trips_25', TIMESTAMPTZ '2025-03-24 13:20:48', 'Carine', 10, 'Teste', 'Teste', '{"original_name": "Carine", "proximo_destino": "Teste"}'::jsonb),
  ('forms_welcome_trips_26', TIMESTAMPTZ '2025-03-28 06:49:00', 'Claudio José Barros de Carvalho', 10, 'Gostamos muito', 'Ainda não decidimos', '{"original_name": "Claudio José Barros de Carvalho", "proximo_destino": "Ainda não decidimos"}'::jsonb),
  ('forms_welcome_trips_27', TIMESTAMPTZ '2025-04-01 06:40:56', 'Maria Helena Venetikides Durigan', 10, 'Tudo 10', NULL, '{"original_name": "Maria Helena Venetikides Durigan"}'::jsonb),
  ('forms_welcome_trips_28', TIMESTAMPTZ '2025-04-01 06:55:04', 'Leandro Cavallim', 10, 'Exceptional', 'Europa ou Australia', '{"original_name": "Leandro Cavallim", "proximo_destino": "Europa ou Australia"}'::jsonb),
  ('forms_welcome_trips_29', TIMESTAMPTZ '2025-04-01 11:11:29', 'SUELI TERESINHA MORAES MUNIZ DA SILVA', 10, 'Ótimo, e recebemos  o maior  da Camila', 'México', '{"original_name": "SUELI TERESINHA MORAES MUNIZ DA SILVA", "proximo_destino": "México"}'::jsonb),
  ('forms_welcome_trips_30', TIMESTAMPTZ '2025-04-02 06:29:33', 'Diego Alves da Cruz', 10, 'Foi simplesmente incrível, todos os hotéis reservado foram sensacionais, pensado em cada detalhe, não sofremos nada em nenhuma hospedagem ou vôo, tudo que queríamos foi considerado e feito da melhor forma para que tivéssemos a melhor experiência possível, vocês realmente conseguiriam isso e eu deixo aqui o meu agradecimento especial para a Barbara que foi sensacional em tudo, pensando em todos os detalhes para que a nossa lua de mel fosse incrível.', 'Queremos ir para a África, ficamos com isso na cabeça de conhecer melhor os países de lá, fazer um safari com as crianças. Este será o nosso próximo destino 🙏', '{"original_name": "Diego Alves da Cruz", "proximo_destino": "Queremos ir para a África, ficamos com isso na cabeça de conhecer melhor os países de lá, fazer um safari com as crianças. Este será o nosso próximo destino 🙏"}'::jsonb),
  ('forms_welcome_trips_31', TIMESTAMPTZ '2025-04-02 06:29:33', 'Diego Alves da Cruz', 10, 'Foi simplesmente incrível, todos os hotéis reservado foram sensacionais, pensado em cada detalhe, não sofremos nada em nenhuma hospedagem ou vôo, tudo que queríamos foi considerado e feito da melhor forma para que tivéssemos a melhor experiência possível, vocês realmente conseguiriam isso e eu deixo aqui o meu agradecimento especial para a Barbara que foi sensacional em tudo, pensando em todos os detalhes para que a nossa lua de mel fosse incrível.', 'Queremos ir para a África, ficamos com isso na cabeça de conhecer melhor os países de lá, fazer um safari com as crianças. Este será o nosso próximo destino 🙏', '{"original_name": "Diego Alves da Cruz", "proximo_destino": "Queremos ir para a África, ficamos com isso na cabeça de conhecer melhor os países de lá, fazer um safari com as crianças. Este será o nosso próximo destino 🙏"}'::jsonb),
  ('forms_welcome_trips_32', TIMESTAMPTZ '2025-04-02 19:36:47', 'Juliana Santana', 10, NULL, 'França', '{"original_name": "Juliana Santana", "proximo_destino": "França"}'::jsonb),
  ('forms_welcome_trips_33', TIMESTAMPTZ '2025-04-02 20:09:54', 'Ludimila fernandes', 9, 'Foi incrível! A Camila faz um trabalho fantástico
