  ('forms_welcome_trips_132', TIMESTAMPTZ '2025-10-29 09:18:52', 'Andrea Sabatella Rodriguez', 10, 'Apenas faltou enviar os embarques do retorno pelo sistema . Mariana me passou qdo solicitei', 'Europa em julho 2026 ( Itália/Londres )', '{"original_name": "Andrea Sabatella Rodriguez", "proximo_destino": "Europa em julho 2026 ( Itália/Londres )"}'::jsonb),
