  ('forms_welcome_trips_182', TIMESTAMPTZ '2026-02-03 08:23:32', 'Carla M M M Rosa', 10, 'A viagem foi ótima, pensada em todos os detalhes, com guias em português e tudo muito bem organizado.', 'Copa do mundo e Med no inverno para esquiar.', '{"original_name": "Carla M M M Rosa", "proximo_destino": "Copa do mundo e Med no inverno para esquiar."}'::jsonb),
