  ('forms_welcome_trips_195', TIMESTAMPTZ '2026-02-19 09:39:18', 'Bruno Bewalski', 10, 'Surpreendente. Muita atenção em todos os sentidos e uma surpresa muito agradável em receber os diversos mimos e presentes desde o início do fechamento do pacote Club Med.', 'Pretendo um verão europeu com minha esposa, filha e mãe.', '{"original_name": "Bruno Bewalski", "proximo_destino": "Pretendo um verão europeu com minha esposa, filha e mãe."}'::jsonb),
  ('forms_welcome_trips_196', TIMESTAMPTZ '2026-02-19 17:13:09', 'Elton Oshiro', 10, NULL, 'Penso em europa', '{"original_name": "Elton Oshiro", "proximo_destino": "Penso em europa"}'::jsonb),
  ('forms_welcome_trips_197', TIMESTAMPTZ '2026-02-19 21:35:09', 'Marcia Luz', 10, 'Passei por vários imprevistos e a Simone não mediu esforços pra nos ajudar em pleno sábado e domingo de carnaval. Isso não tem preço .', 'Tailândia', '{"original_name": "Marcia Luz", "proximo_destino": "Tailândia"}'::jsonb),
  ('forms_welcome_trips_198', TIMESTAMPTZ '2026-02-20 16:34:56', 'Anderson Persegona Amorim', 10, 'Fantastico', 'Barcelona', '{"original_name": "Anderson Persegona Amorim", "proximo_destino": "Barcelona"}'::jsonb),
  ('forms_welcome_trips_199', TIMESTAMPTZ '2026-02-20 16:35:31', 'Paula Curi Reis Ribeiro do Valle', 10, 'A experiência foi impecável do início ao fim. Os hotéis eram ótimos, muito confortáveis e bem localizados, com atendimento atencioso e boa estrutura. Tudo ocorreu perfeitamente. Foi uma viagem incrível!!!', 'Estamos ainda pensando, mas será lua de mel em maio de 2027 💖💖', '{"original_name": "Paula Curi Reis Ribeiro do Valle", "proximo_destino": "Estamos ainda pensando, mas será lua de mel em maio de 2027 💖💖"}'::jsonb),
  ('forms_welcome_trips_200', TIMESTAMPTZ '2026-02-22 19:02:53', 'Vanessa Alberti', 10, NULL, NULL, '{"original_name": "Vanessa Alberti"}'::jsonb),
  ('forms_welcome_trips_201', TIMESTAMPTZ '2026-03-02 16:35:08', 'João Batista Lopes dos Santos', 10, 'Foi tudo bem confirme o combinado', NULL, '{"original_name": "João Batista Lopes dos Santos"}'::jsonb),
  ('forms_welcome_trips_202', TIMESTAMPTZ '2026-03-04 16:49:52', 'Daphne Keller', 10, 'Kissia e o time pós venda são sensacionais...só agradecer a atenção e o profissionalismo do time aí!!!', 'Amazônia', '{"original_name": "Daphne Keller", "proximo_destino": "Amazônia"}'::jsonb),
  ('forms_welcome_trips_203', TIMESTAMPTZ '2026-03-05 10:00:16', 'Fabiano Veiga Oliva', 10, 'Viagem foi sensacional! A cidade muito linda, muitos pontos turísticos, porém uma cidade “cara”! Hotel bem localizado, porém achei que os serviços do hotel poderiam ser melhores, pra ter ideia se recusaram a servir gelo! No mais foi tudo bem', 'Chile', '{"original_name": "Fabiano Veiga Oliva", "proximo_destino": "Chile"}'::jsonb),
  ('forms_welcome_trips_204', TIMESTAMPTZ '2026-03-12 15:45:46', 'João Luiz Martins', 10, 'Otimo atendimento e disponibilidade da concierge.', 'Miami/Orlando', '{"original_name": "João Luiz Martins", "proximo_destino": "Miami/Orlando"}'::jsonb),
  ('forms_welcome_trips_205', TIMESTAMPTZ '2026-03-19 20:12:58', 'Leonardo Monteiro', 10, 'perfeito. toda atenção da equipe', 'Buenos Aires', '{"original_name": "Leonardo Monteiro", "proximo_destino": "Buenos Aires"}'::jsonb),
  ('forms_welcome_trips_206', TIMESTAMPTZ '2026-03-21 18:26:20', 'Leandro Novello', 10, 'Tudo certo. Cronograma cumprido com excelência, e muito prestativos.', 'Portugal, Marrocos', '{"original_name": "Leandro Novello", "proximo_destino": "Portugal, Marrocos"}'::jsonb),
  ('forms_welcome_trips_207', TIMESTAMPTZ '2026-03-23 07:35:00', 'Lucas Novello', 10, 'A experiência foi ótima, sempre tivemos suporte quando precisamos.', NULL, '{"original_name": "Lucas Novello"}'::jsonb),
  ('forms_welcome_trips_208', TIMESTAMPTZ '2026-03-30 16:52:15', 'Wanderley kampa ribas', 8, 'Ficar atento porque o tempo de conexão em bs as é muito curto. Ate fazer aduana quase perdemos o voo. Só conseguimos porque entramos numa outra fila e com muita dificuldade (muito bate boca) fomos atendidos. Descobrimos também outro passeio em el calafate que oferece 3 ou 4 glaciais no mesmo dia, seria interessante oferecer este pacote. No restante tudo certo', 'Ainda nao sabemos', '{"original_name": "Wanderley kampa ribas", "proximo_destino": "Ainda nao sabemos"}'::jsonb),
  ('forms_welcome_trips_209', TIMESTAMPTZ '2026-03-30 17:07:56', 'Ana Paula Stephanes', 10, NULL, NULL, '{"original_name": "Ana Paula Stephanes"}'::jsonb),
  ('forms_welcome_trips_210', TIMESTAMPTZ '2026-03-30 17:12:23', 'Sueli Terezinha branco procop', 10, 'Otimo atendimento. Qlqr duvida era só ligar de onde estivesse para ser atendida.', 'Em planejamento, talvez esse mesmo roteiro Maceio/ Porto de Galinhas. Ou nao....', '{"original_name": "Sueli Terezinha branco procop", "proximo_destino": "Em planejamento, talvez esse mesmo roteiro Maceio/ Porto de Galinhas. Ou nao...."}'::jsonb),
  ('forms_welcome_trips_211', TIMESTAMPTZ '2026-03-30 18:36:57', 'Marina Roncaglio de Carvalho', 10, 'Muito boa! =)', NULL, '{"original_name": "Marina Roncaglio de Carvalho"}'::jsonb),
  ('forms_welcome_trips_212', TIMESTAMPTZ '2026-03-30 19:00:46', 'Leandra Rubert Campos', 10, 'Fomos bem atendidos e auxiliados', 'Chile', '{"original_name": "Leandra Rubert Campos", "proximo_destino": "Chile"}'::jsonb),
  ('forms_welcome_trips_213', TIMESTAMPTZ '2026-03-31 07:47:33', 'Wilson dos Santos Campos Jr', 10, 'Uma boa experiência, tudo ocorreu como planejado', 'Chile', '{"original_name": "Wilson dos Santos Campos Jr", "proximo_destino": "Chile"}'::jsonb),
  ('forms_welcome_trips_214', TIMESTAMPTZ '2026-03-31 22:19:10', 'paula de campos borges', 10, NULL, NULL, '{"original_name": "paula de campos borges"}'::jsonb)
    ),
    normalized AS (
      SELECT
        s.*,
        regexp_replace(lower(unaccent(trim(s.full_name))), '\s+', ' ', 'g') AS norm_name
      FROM source s
    ),
    candidates AS (
      SELECT
        n.source_external_id,
        n.responded_at,
        n.full_name,
        n.score,
        n.comment,
        n.proximo_destino,
        n.raw_payload,
        c.id AS card_id,
        c.pessoa_principal_id AS contact_id,
        ROW_NUMBER() OVER (
          PARTITION BY n.source_external_id
          ORDER BY c.created_at DESC NULLS LAST
        ) AS rn
      FROM normalized n
      LEFT JOIN public.cards c ON c.org_id = v_org_id
        AND c.archived_at IS NULL
        AND EXISTS (
          SELECT 1 FROM public.contatos co
          WHERE co.id = c.pessoa_principal_id
            AND regexp_replace(
                  lower(unaccent(trim(coalesce(co.nome, '') || ' ' || coalesce(co.sobrenome, '')))),
                  '\s+', ' ', 'g'
                ) = n.norm_name
        )
    )
    SELECT source_external_id, responded_at, full_name, score, comment, proximo_destino, raw_payload, card_id, contact_id
    FROM candidates
    WHERE rn = 1
    ORDER BY responded_at
  LOOP
    v_card_id := r_row.card_id;
    v_contact_id := r_row.contact_id;

    INSERT INTO public.nps_surveys
      (org_id, card_id, contact_id, channel, sent_at, source_external_id, created_at)
    VALUES
      (v_org_id, v_card_id, v_contact_id, 'form', r_row.responded_at, r_row.source_external_id, r_row.responded_at)
    ON CONFLICT (source_external_id) WHERE source_external_id IS NOT NULL DO NOTHING
    RETURNING id INTO v_survey_id;

    IF v_survey_id IS NULL THEN
      SELECT id INTO v_survey_id FROM public.nps_surveys
      WHERE source_external_id = r_row.source_external_id LIMIT 1;
    END IF;

    INSERT INTO public.nps_responses
      (survey_id, org_id, card_id, score, comment, proximo_destino, responded_at, raw_payload, created_at)
    VALUES
      (v_survey_id, v_org_id, v_card_id, r_row.score, r_row.comment, r_row.proximo_destino, r_row.responded_at, r_row.raw_payload, r_row.responded_at)
    ON CONFLICT (survey_id) DO NOTHING;

    IF v_card_id IS NULL THEN
      v_unlinked_count := v_unlinked_count + 1;
    ELSE
      v_matched_count := v_matched_count + 1;
    END IF;
  END LOOP;

  RAISE NOTICE 'NPS backfill terminado: % com card vinculado, % sem card (total %).',
    v_matched_count, v_unlinked_count, v_matched_count + v_unlinked_count;
END $$;

COMMIT;
